import Link from "next/link";
import styles from "./contact.module.css";
import Image from "next/image";

function Contact() {
  return (
    <div>
      <div className={styles.container}>
        <Image
          src="/mail.png"
          alt="Picture of the author"
          width={50}
          height={50}
        />

        <Image
          src="/twitter.png"
          alt="Picture of the author"
           width={50}
          height={50}
        />

        <Image
          src="/github.png"
          alt="Picture of the author"
           width={50}
          height={50}
        />

        <Image
          src="/insta.png"
          alt="Picture of the author"
           width={50}
          height={50}
        />

        <Image
          src="/linkedin.png"
          alt="Picture of the author"
           width={50}
          height={50}
        />
      </div>
    </div>
  );
}

export default Contact;
